CREATE TABLE public.business_project_live_summary ( project_id uuid PRIMARY KEY REFERENCES public.business_projects(id) ON DELETE CASCADE, summary_markdown text, status_json jsonb, last_event_id uuid, last_event_at timestamptz, updated_at timestamptz NOT NULL DEFAULT now(), model_used text ); ALTER TABLE public.business_project_live_summary ENABLE ROW LEVEL SECURITY; CREATE POLICY "ls_all" ON public.business_project_live_summary FOR ALL TO authenticated USING ( EXISTS (SELECT 1 FROM public.business_projects bp WHERE bp.id = business_project_live_summary.project_id AND bp.user_id = auth.uid()) ) WITH CHECK ( EXISTS (SELECT 1 FROM public.business_projects bp WHERE bp.id = business_project_live_summary.project_id AND bp.user_id = auth.uid()) ); ALTER TABLE public.business_project_timeline ADD COLUMN IF NOT EXISTS analysis_json jsonb, ADD COLUMN IF NOT EXISTS impact_scope text, ADD COLUMN IF NOT EXISTS impact_prd text, ADD COLUMN IF NOT EXISTS needs_regeneration boolean DEFAULT false, ADD COLUMN IF NOT EXISTS importance_score integer DEFAULT 0